//点击获取材质开始
//技术写的随机抽取方法,点击获取材质会直接执行
function czsc(path) {
    var folder = new Folder(path);
    var fileList = folder.getFiles(); // 获取文件夹中的所有文件
    for (var i = 0; i < fileList.length; i++) {
        addPic(fileList[i]); // 将每个文件传递给 addPic 函数
    }

    function addPic(file) {
        open(file); // 打开传入的文件
        var openedFileName = file.name;
        app.activeDocument.activeLayer.copy();
        try {
            app.activeDocument = app.documents.getByName("土拨鼠效果图.psd");
        } catch (e) {
            app.activeDocument = app.documents.getByName("土拨鼠效果图");
        }
        var pastedLayer = app.activeDocument.paste();
        // 设置粘贴图层的名称
        var firstChar = openedFileName.charAt(0).toLowerCase();
        if (firstChar === 'l') {
            pastedLayer.name = "绿地材质";
        } else if (firstChar === 'd') {
            pastedLayer.name = "道路材质";
        } else if (firstChar === 'h') {
            pastedLayer.name = "河水材质";
        } else if (firstChar === 'g') {
            pastedLayer.name = "广场材质";
        }
        pastedLayer.move(app.activeDocument.layerSets.getByName("材质"), ElementPlacement.INSIDE);
        app.documents.getByName(openedFileName).close(SaveOptions.DONOTSAVECHANGES);
    }

    //下面是我自己写的课程处理方法，不用动就可以
    caizhifenlei();
}

