//第二页  索引图  点击导入素材的那个

function zong(a) {
    try {
        var filePath = decodeURI(decodeURIComponent(a));
        var currentDocument = app.activeDocument;
        var randomFileName = decodeURI(filePath.split('/').pop());
        open(File(filePath));
        app.documents.getByName(randomFileName).activeLayer.copy();
        app.activeDocument = currentDocument;
        currentDocument.paste();
        app.documents.getByName(randomFileName).close(SaveOptions.DONOTSAVECHANGES);
    } catch (error) {
        alert("操作太频繁啦~,请让程序缓口气");
    }
}

function readXMLFile(filePath) {
    var file = new File(filePath);
    if (file.exists) {
        file.open('r');
        var content = file.read();
        file.close();
        return content;
    }
    return '';
}

//打开源文件
function openSourceFile(filePath) {
    var file = new File(filePath);
    open(File(file));
}

function customAlert(text) {
    var win = new Window("dialog", "提示");
    win.add("statictext", undefined, text);

    // 添加按钮并绑定关闭事件
    var btn = win.add("button", undefined, "确定");
    btn.onClick = function () {
        win.close(); // 关键：点击后关闭窗口
    };

    win.show(); // 显示窗口（阻塞式，直到关闭）
}

function saveFile(filePath, base64Str) {
    try {
        // 路径解码（仅一次 decodeURIComponent）
        var decodedPath = decodeURIComponent(filePath);
        var file = new File(decodedPath);
        if (file.error) return "ERROR: 路径错误 - " + file.error;

        // Base64 解码
        var binaryString = safeDecodeBase64(base64Str);
        if (!binaryString) return "ERROR: Base64 无效";

        // 原子写入（避免数据不完整）
        var tempFile = new File(decodedPath + ".tmp");
        tempFile.encoding = "BINARY";
        tempFile.open("w");
        tempFile.write(binaryString);
        tempFile.close();
        // 重命名确保写入完成
        tempFile.rename(decodedPath);
        return "SUCCESS";
    } catch (e) {
        return "ERROR";
    }
}

// 修复后的 safeDecodeBase64 函数
function safeDecodeBase64(input) {
    var keyStr = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=";
    var output = "";
    var chr1, chr2, chr3;
    var enc1, enc2, enc3, enc4;
    var i = 0;

    // 预处理：移除所有非 Base64 字符并自动补足 "="
    input = input.replace(/[^A-Za-z0-9\+\/]/g, "");
    var pad = input.length % 4;
    if (pad) input += (pad === 1 ? "===" : "==");

    while (i < input.length) {
        enc1 = keyStr.indexOf(input.charAt(i++));
        enc2 = keyStr.indexOf(input.charAt(i++));
        enc3 = keyStr.indexOf(input.charAt(i++));
        enc4 = keyStr.indexOf(input.charAt(i++));

        // 验证有效性
        if (enc1 < 0 || enc2 < 0 || enc3 < 0 || enc4 < 0) {
            return null;
        }

        chr1 = (enc1 << 2) | (enc2 >> 4);
        chr2 = ((enc2 & 15) << 4) | (enc3 >> 2);
        chr3 = ((enc3 & 3) << 6) | enc4;

        output += String.fromCharCode(chr1);
        if (enc3 !== 64) output += String.fromCharCode(chr2);
        if (enc4 !== 64) output += String.fromCharCode(chr3);
    }
    return output;
}